**AI Implementation:**
```typescript
// @psyforge/ai-assistant
export interface DesignCommand {
  intent: 'add_stimulus' | 'add_trial' | 'modify_timing' | 'add_condition';
  parameters: Record<string, any>;
  context: ExperimentContext;
}

export class AIDesignAssistant {
  constructor(apiKey: string, model: 'gpt-4' | 'claude-3');

  // Parse natural language into structured command
  async parseCommand(input: string, context: ExperimentContext): Promise<DesignCommand>;

  // Generate ForgeScript code for command
  async generateCode(command: DesignCommand): Promise<string>;

  // Validate generated code
  async validateCode(code: string): Promise<ValidationResult>;

  // Suggest improvements or alternatives
  async suggestImprovements(experiment: CompiledExperiment): Promise<Suggestion[]>;
}

// Example usage
const assistant = new AIDesignAssistant(process.env.OPENAI_API_KEY, 'gpt-4');

// "Add 20 Stroop trials with equal numbers of congruent and incongruent"
const command = await assistant.parseCommand(userInput, currentExperiment);
const code = await assistant.generateCode(command);
const validation = await assistant.validateCode(code);

if (validation.valid) {
  applyCodeToExperiment(code);
} else {
  showValidationErrors(validation.errors);
}
```

